import React, { useEffect, useState } from "react";
import { Link, useNavigate } from 'react-router-dom';
import alertPopUp from 'sweetalert2';
import withReactContent from 'sweetalert2-react-content';
import { deleteModalSwal, epochTogmt, errorMessagePopUp, stausOptions } from "src/utils/Common";
import { CButton } from "@coreui/react";
import { deleteTrivia, getAllTriviaList } from "src/components/services/TriviaApi";
import DataTable from "react-data-table-component";
import { customStyles } from "../../utils/tableCustomStyles";
import { tableTriviaConstant } from "./tableTriviaConstant";
import authService from "src/auth/auth.service";
import Select from 'react-select';
import { v4 as uuidv4 } from 'uuid';
import { getEnableCategory } from "src/components/services/CategoryApi";
import { FilterComponent } from "src/utils/FilterComponent";

const MySwal = withReactContent(alertPopUp);

const TriviaList = () => {
    const [rowData, setRowData] = useState([]);
    const [selectData, setSelectData] = useState({ category: { value: 'ALL', label: 'ALL' }, status: { value: 'ALL', label: 'ALL' } });
    const [categoryOption, setCategoryOption] = useState([{ value: 'ALL', label: 'ALL' }]);
    const [filterData, setFilterData] = useState({filterText: "", isSearchDisabled: true, clearField: uuidv4()});
    const [perPage, setPerPage] = useState(10);
    const [loading, setLoading] = useState(false);
    const [totalRows, setTotalRows] = useState(0);
    const navigate = useNavigate();

    useEffect(() => {
        getCategoryData();
    }, []);

    useEffect(() => {
        fetchTriviaList(1, 10);
    }, [selectData, filterData?.clearField]);

    const handleDelete = async (id) => {
        const response = await deleteTrivia(id);
        if (response?.code === 200) {
            fetchTriviaList(1, 10);
        }
    }

    const fetchTriviaList = async (page, size) => {
        const response = await getAllTriviaList({ category: selectData?.category?.value, status: selectData?.status?.value, query: filterData?.filterText, page: page, size: size });
        if (response?.code === 200) {
            // response?.results && response?.results?.content.map((item) => {
            //     let count = 0;
            //     let output = [];
            //     item.tags && item?.tags?.map((data, index) => {
            //         if (index < 1) {
            //             output.push(data);
            //         } else {
            //             count = count + 1;
            //         }
            //     });
            //     data.push({ title: item?.title, category: item?.category, coverImageUrl: item?.coverImageUrl, id: item?._id, tags: count === 0 ? output : output + ", +" + count, "status": item?.status, "createTime": epochTogmt(item?.createTime) });
            // });
            setRowData(response?.results?.content);
            setLoading(false);
            setTotalRows(response?.results?.totalElements);
        }
    };

    const getCategoryData = async () => {
        let categories = [];
        let response = await getEnableCategory();
        if (response?.code === 200) {
            categories = response?.results && response?.results.map((data) => { return { label: data.name, value: data._id } })
            setCategoryOption([...categoryOption, ...categories]);
        }
    }

    const handleSelectChange = (data, type) => {
        setSelectData({ ...selectData, [type]: data });
    }

    const handleConfirmModal = (id) => {
        const handleConfirm = async () => {
            const swalval = await MySwal.fire(deleteModalSwal);
            if (swalval && swalval.value === true) {
                handleDelete(id)
            }
        };
        handleConfirm();
    };

    const handleClearSearch = () => {
        setFilterData((filterData) => ({ ...filterData, filterText: "", isSearchDisabled: true, clearField: uuidv4()}));
    }

    const handleChangeFilter = (event) => {
        let value = event.target.value.trimStart().replace(/[`~!@#$%^&*()_|+\-=?;:'",.<>\{\}\[\]\\\/]/gi, '');
        setFilterData((filterData) => ({ ...filterData, filterText: value, isSearchDisabled: value === ""}));
    };

    const getSubHeaderComponent = () => {
        return (
            <React.Fragment>
                <div>
                    <FilterComponent
                        onFilter={handleChangeFilter}
                        searchType={'Search by title'}
                        //onClear={this.handleClear}
                        filterText={filterData?.filterText}
                    />
                    <span class="search-close" onClick={() => handleClearSearch()}></span>
                </div>
            </React.Fragment>
        );
    };

    const actionButton = () => {
        return (
            <React.Fragment>
                {getSubHeaderComponent()}
                <CButton type="submit" color="primary" className="addRoleGlobal" style={{ float: "right" }} disabled={filterData?.isSearchDisabled} onClick={ ()=> fetchTriviaList(1, 10)}>
                    <i class="fa fa-search" /> Search
                </CButton>
            </React.Fragment>
        );
    };

    const handlePageChange = page => {
        fetchTriviaList(page, perPage);
    };

    const handlePerRowsChange = async (newPerPage, page) => {
        setPerPage(newPerPage);
        fetchTriviaList(page, newPerPage);
    };

    return (<div className='row'>
        <div className="col-md-12 mb-3">
            <div className="filterSection">
                <div className="col-md-3" style={{ marginRight: "10px" }}>
                    <Select
                        options={categoryOption}
                        placeholder={"Filter by category"}
                        value={selectData.category}
                        onChange={(selectedOption) => handleSelectChange(selectedOption, 'category')}
                        classNamePrefix="select"
                        styles={{
                            option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                const color = '#03a68059';
                                return {
                                    ...styles,
                                    backgroundColor: isDisabled
                                        ? null
                                        : isSelected
                                            ? '#03a68059'
                                            : isFocused
                                                ? '#03a68059'
                                                : null,
                                    color: isDisabled
                                        ? '#ccc'
                                        : isSelected
                                            ? color > 2
                                                ? '#00374d'
                                                : '#00374d'
                                            : data.color,
                                    cursor: isDisabled ? 'not-allowed' : 'default',

                                    ':active': {
                                        ...styles[':active'],
                                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                    },
                                };
                            },
                        }}
                    />
                </div>
                <div className="col-md-2">
                    <Select
                        options={stausOptions}
                        placeholder={"Filter by status"}
                        value={selectData.status}
                        onChange={(selectedOption) => handleSelectChange(selectedOption, 'status')}
                        classNamePrefix="select"
                        styles={{
                            option: (styles, { data, isDisabled, isFocused, isSelected }) => {
                                const color = '#03a68059';
                                return {
                                    ...styles,
                                    backgroundColor: isDisabled
                                        ? null
                                        : isSelected
                                            ? '#03a68059'
                                            : isFocused
                                                ? '#03a68059'
                                                : null,
                                    color: isDisabled
                                        ? '#ccc'
                                        : isSelected
                                            ? color > 2
                                                ? '#00374d'
                                                : '#00374d'
                                            : data.color,
                                    cursor: isDisabled ? 'not-allowed' : 'default',

                                    ':active': {
                                        ...styles[':active'],
                                        backgroundColor: !isDisabled && (isSelected ? '#03a68059' : '#03a68059'),
                                    },
                                };
                            },
                        }}
                    />
                </div>
            </div>
        </div>
        <div className="col2Large">
            <DataTable
                title="Trivia"
                columns={tableTriviaConstant(fetchTriviaList, handleConfirmModal)}
                data={rowData}
                customStyles={customStyles}
                actions={actionButton()}
                pagination
                paginationPerPage={perPage}
                pointerOnHover
                fixedHeader
                noContextMenu
                fixedHeaderScrollHeight={"calc(100vh - 226px)"}
                progressPending={loading}
                paginationServer
                paginationTotalRows={totalRows}
                onChangeRowsPerPage={handlePerRowsChange}
                onChangePage={handlePageChange}
            />
        </div>
        {authService.getPermission("TRIVIA_CREATE") && <div className='col-sm-12'>
            <Link to={"/trivia/create"}>
                <CButton type="submit" color="primary" className="create-btn" style={{ float: "right" }}>
                    {"+ Create Trivia"}
                </CButton>
            </Link>
        </div>}
    </div>)
}

export default TriviaList;
